    <Comp
      data-slot="sidebar-menu-button"
      data-sidebar="menu-button"
      data-size={size}
      data-active={isActive}
      className={cn(sidebarMenuButtonVariants({ variant, size }), className)}
      {...props}
    />
  )

  if (!tooltip) {
    return button
  }

  // Conditional wrapper with context value
  return (
    <Tooltip>
      <TooltipTrigger asChild>{button}</TooltipTrigger>
      <TooltipContent
        side="right"
        align="center"
        hidden={state !== "collapsed" || isMobile}
        {...tooltip}
      />
    </Tooltip>
  )
}
```

#### Nested Data Attributes:
```typescript
function Sidebar({
  side = "left",
  variant = "sidebar",
  collapsible = "offcanvas",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  side?: "left" | "right"
  variant?: "sidebar" | "floating" | "inset"
  collapsible?: "offcanvas" | "icon" | "none"
}) {
  const { isMobile, state, openMobile, setOpenMobile } = useSidebar()

  return (
    <div
      className="group peer hidden text-sidebar-foreground md:block"
      data-state={state}
      data-collapsible={state === "collapsed" ? collapsible : ""}
      data-variant={variant}
      data-side={side}
      data-slot="sidebar"
    >
      {/* ... */}
    </div>
  )
}
```

---

### 5. **Radix UI Wrapper Pattern (No Custom Context)**
**Locations:** Accordion, Popover, Dialog, Dropdown Menu, Select, HoverCard, NavigationMenu

These components wrap Radix UI primitives directly without custom React context:

#### Accordion Example:
```typescript
function Accordion({
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "flex flex-1 items-start justify-between gap-4 rounded-md py-4 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-180",
          className
        )}
        {...props}
      >
        {children}
        <ChevronDownIcon className="pointer-events-none size-4 shrink-0 translate-y-0.5 text-muted-foreground transition-transform duration-200" />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}
```

---

### 6. **Data-Slot Attributes Pattern**
Every component uses `data-slot` to identify itself for CSS targeting and testing:

```typescript
data-slot="carousel"
data-slot="carousel-item"
data-slot="tabs"
data-slot="tabs-list"
data-slot="tabs-trigger"
data-slot="accordion-trigger"
data-slot="sidebar-menu-button"
data-slot="popover-content"
data-slot="dialog-content"
data-slot="dropdown-menu-item"
```

Combined with Tailwind's `data-[...]` selectors for styling:
```typescript
"data-[state=open]:bg-accent data-[state=open]:text-accent-foreground"
"group-data-[orientation=vertical]/tabs:w-full"
"peer-data-[active=true]/menu-button:text-sidebar-accent-foreground"
```

---

### 7. **Key Import Patterns**
```typescript
// Radix UI imports
import { Tabs as TabsPrimitive } from "radix-ui"
import { Accordion as AccordionPrimitive } from "radix-ui"
import { Dialog as DialogPrimitive } from "radix-ui"
import { DropdownMenu as DropdownMenuPrimitive } from "radix-ui"
import { Select as SelectPrimitive } from "radix-ui"
import { NavigationMenu as NavigationMenuPrimitive } from "radix-ui"
import { HoverCard as HoverCardPrimitive } from "radix-ui"
import { Popover as PopoverPrimitive } from "radix-ui"

// CVA for variants
import { cva, type VariantProps } from "class-variance-authority"

// Utilities
import { cn } from "@/lib/utils"

// Radix Slot for "asChild" pattern
import { Slot } from "radix-ui"
```

---

### 8. **Key Patterns Summary**

| Pattern | Used By | Purpose |
|---------|---------|---------|
| **Custom React Context** | Carousel, Sidebar | Share complex state and imperative APIs across children |
| **Error-throwing useHook** | useCarousel(), useSidebar() | Prevent misuse outside provider, clear error messages |
| **CVA (Class Variance Authority)** | Tabs, Sidebar, Select, Dropdown | Manage multiple className variants systematically |
| **Data Attributes** | All components | CSS state selectors, prop propagation without context |
| **Radix Primitive Wrapping** | Accordion, Popover, Dialog, etc. | Delegate accessibility and behavior to primitives |
| **Controlled/Uncontrolled** | Sidebar | Support both controlled and uncontrolled usage |
| **React.useMemo for Context** | Sidebar | Prevent unnecessary re-renders of consumers |
| **Radix Slot + asChild** | Breadcrumb, Sidebar | Polymorphic component pattern with Comp selection |
| **Portal wrapping** | Popover, Dialog, DropdownMenu, Select | Handle layered UI (modals, dropdowns, tooltips) |
| **Callback memoization** | Carousel, Sidebar | Prevent stale closures in event listeners |

---

### 9. **Orientation & Variant Prop Handling**

**Explicit Prop (Carousel):**
```typescript
orientation: "horizontal" | "vertical"
// Used directly in context and passed to children
```

**Data Attribute (Tabs):**
```typescript
data-orientation={orientation}
// Consumed via CSS selectors in child classes
data-[orientation=vertical]/tabs:flex-col
```

**CVA Variant Props (Sidebar):**
```typescript
variant: "sidebar" | "floating" | "inset"
collapsible: "offcanvas" | "icon" | "none"
// Passed to cva() function which generates conditional classes
```

---

This comprehensive pattern demonstrates shadcn/ui's philosophy: **minimal but powerful abstractions built on Radix UI primitives, with Tailwind CSS for styling and strategic use of React Context for complex state management.**

